'use client';
import { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

interface LetterMirrorProps {
  onGameComplete: (stats: { errors: number; reaction_time: number; attempts: number; mirror_error_rate: number }) => void;
}

const ROUNDS = 5;

// Letters commonly confused (b/d, p/q)
const PAIRS = [
  { correct: 'b', incorrect: 'd' },
  { correct: 'd', incorrect: 'b' },
  { correct: 'p', incorrect: 'q' },
  { correct: 'q', incorrect: 'p' },
];

export default function LetterMirrorGame({ onGameComplete }: LetterMirrorProps) {
  const [round, setRound] = useState(0);
  const [targetPair, setTargetPair] = useState(PAIRS[0]);
  const [options, setOptions] = useState<string[]>([]);
  const [shake, setShake] = useState(false);
  
  // Stats
  const [startTime, setStartTime] = useState(Date.now());
  const [errors, setErrors] = useState(0);
  const [mirrorErrors, setMirrorErrors] = useState(0);
  const [attempts, setAttempts] = useState(0);
  const [totalReactionTime, setTotalReactionTime] = useState(0);

  // Initialize round
  useEffect(() => {
    if (round < ROUNDS) {
      const pair = PAIRS[Math.floor(Math.random() * PAIRS.length)];
      setTargetPair(pair);
      
      const newOptions = [pair.correct, pair.incorrect, pair.incorrect, pair.correct === 'b' ? 'q' : 'p'];
      setOptions(newOptions.sort(() => Math.random() - 0.5));
      setStartTime(Date.now());
    } else {
      onGameComplete({
        errors,
        reaction_time: totalReactionTime / ROUNDS,
        attempts,
        mirror_error_rate: mirrorErrors / Math.max(1, errors)
      });
    }
  }, [round]);

  const handleSelection = (selected: string) => {
    setAttempts(prev => prev + 1);
    const reactionTime = (Date.now() - startTime) / 1000;

    if (selected === targetPair.correct) {
      setTotalReactionTime(prev => prev + reactionTime);
      setRound(prev => prev + 1);
    } else {
      setErrors(prev => prev + 1);
      if (selected === targetPair.incorrect) {
        setMirrorErrors(prev => prev + 1);
      }
      // Trigger shake animation
      setShake(true);
      setTimeout(() => setShake(false), 500);
    }
  };

  if (round >= ROUNDS) return null;

  return (
    <div className="flex flex-col items-center justify-center p-4 relative overflow-hidden">
      {/* Magical Background Decorations */}
      <div className="absolute inset-0 pointer-events-none">
        <div className="absolute top-0 left-1/4 w-32 h-32 bg-white/10 blur-2xl rounded-full animate-pulse-soft" />
        <div className="absolute bottom-0 right-1/4 w-40 h-40 bg-white/10 blur-3xl rounded-full animate-blob [animation-delay:1s]" />
      </div>

      <motion.div 
        animate={{ x: shake ? [-10, 10, -10, 10, 0] : 0 }}
        className="relative z-10 w-full flex flex-col items-center"
      >
        <div className="glass-card px-12 py-8 mb-12 flex flex-col items-center border-white/50 bg-white/20 backdrop-blur-xl shadow-2xl">
          <h3 className="text-3xl font-black text-white mb-4 tracking-tight drop-shadow-md">
            Find the Magic Letter
          </h3>
          <div className="text-8xl font-black text-primary p-8 bg-white/90 rounded-[2rem] shadow-inner relative group">
             <span className="relative z-10">{targetPair.correct}</span>
             <div className="absolute inset-0 bg-primary/20 blur-xl opacity-0 group-hover:opacity-100 transition-opacity rounded-full animate-pulse" />
             {/* Sparkles */}
             <div className="absolute -top-4 -right-4 text-4xl animate-float">✨</div>
             <div className="absolute -bottom-4 -left-4 text-4xl animate-float [animation-delay:1s]">✨</div>
          </div>
        </div>
        
        <div className="grid grid-cols-2 gap-8 w-full max-w-lg">
          <AnimatePresence mode="wait">
            {options.map((option, idx) => (
              <motion.button
                key={`${round}-${idx}`}
                initial={{ opacity: 0, scale: 0.5, rotateY: 90 }}
                animate={{ opacity: 1, scale: 1, rotateY: 0 }}
                whileHover={{ scale: 1.05, rotateY: -10 }}
                whileTap={{ scale: 0.95 }}
                onClick={() => handleSelection(option)}
                className="bg-white/10 backdrop-blur-md border border-white/30 shadow-[0_15px_30px_rgba(0,0,0,0.1)] rounded-[2.5rem] h-40 text-8xl font-black text-white hover:bg-white/30 transition-all flex items-center justify-center relative group overflow-hidden"
              >
                {/* Mirror Reflection Overlay */}
                <div className="absolute inset-0 bg-gradient-to-tr from-transparent via-white/5 to-white/20 opacity-0 group-hover:opacity-100 transition-opacity" />
                <span className="relative z-10 drop-shadow-lg">{option}</span>
              </motion.button>
            ))}
          </AnimatePresence>
        </div>
      </motion.div>
    </div>
  );
}

'use client';
import { useState, useEffect } from 'react';
