             transition={{ duration: 5, repeat: Infinity, ease: "easeInOut" }}
             fill="#87CEEB"
           />
           <motion.circle cx="100" cy="100" r="40" fill="white" animate={{ x: [0, 50, 0] }} transition={{ duration: 20, repeat: Infinity }} />
           <motion.circle cx="600" cy="150" r="60" fill="white" animate={{ x: [0, -70, 0] }} transition={{ duration: 25, repeat: Infinity }} />
        </svg>
      </div>

      <motion.div 
        animate={{ x: shake ? [-10, 10, -10, 10, 0] : 0 }}
        className="relative z-10 w-full flex flex-col items-center"
      >
        <div className="glass-card bg-white/30 backdrop-blur-md p-8 mb-12 flex flex-col items-center border-white/50 rounded-[3rem] shadow-2xl">
          <h3 className="text-3xl font-black text-white mb-6 tracking-tight drop-shadow-md text-center">
