          </h3>
          <div className="flex items-center gap-6 p-8 bg-white/80 rounded-[2.5rem] shadow-inner">
             <div className="flex flex-col items-center">
                <span className="text-5xl font-black text-secondary">{targetNumber - 2}</span>
                <span className="text-xs font-bold text-slate-400 mt-1 uppercase tracking-widest">Step 1</span>
             </div>
             <span className="text-4xl text-slate-300 font-bold">➔</span>
             <div className="flex flex-col items-center">
                <span className="text-5xl font-black text-secondary">{targetNumber - 1}</span>
                <span className="text-xs font-bold text-slate-400 mt-1 uppercase tracking-widest">Step 2</span>
             </div>
             <span className="text-4xl text-slate-300 font-bold">➔</span>
             <div className="w-16 h-16 bg-accent-yellow rounded-2xl flex items-center justify-center animate-bounce-soft shadow-lg border-4 border-white">
                <span className="text-3xl font-black text-white">?</span>
             </div>
          </div>
        </div>
        
        <div className="flex flex-wrap justify-center gap-10">
          <AnimatePresence mode="wait">
            {options.map((option, idx) => (
              <motion.button
                key={`${round}-${idx}`}
                initial={{ y: 100, opacity: 0, scale: 0.5 }}
                animate={{ y: 0, opacity: 1, scale: 1 }}
                whileHover={{ y: -15, scale: 1.1 }}
                whileTap={{ scale: 0.9 }}
                onClick={() => handleSelection(option)}
                className="relative group h-32 w-32 md:h-40 md:w-40"
              >
                {/* Island Platform */}
                <div className="absolute inset-x-0 bottom-0 h-12 bg-primary-dark rounded-full group-hover:h-16 transition-all shadow-2xl" />
                <div className="absolute inset-0 bg-accent-green border-4 border-white rounded-full flex items-center justify-center shadow-xl group-hover:bg-primary transition-colors">
                   <span className="text-5xl md:text-7xl font-black text-white drop-shadow-xl">{option}</span>
                </div>
                {/* Tiny Tree for Island Effect */}
                <div className="absolute -top-4 -right-2 text-4xl group-hover:scale-125 transition-transform animate-wiggle">🏝️</div>
              </motion.button>
            ))}
          </AnimatePresence>
        </div>
      </motion.div>
    </div>
  );
}

import { create } from 'zustand';
import en from '../localization/en.json';
import hi from '../localization/hi.json';

type Language = 'en' | 'hi';

interface LanguageState {
  language: Language;
  t: (key: string) => string;
  setLanguage: (lang: Language) => void;
  toggleLanguage: () => void;
}

const translations = { en, hi };

export const useLanguageStore = create<LanguageState>((set, get) => ({
  language: 'en',
  t: (keyPath: string) => {
    const { language } = get();
    const dictionary: any = translations[language];
    
    // Simple dot notation parser (e.g., 'landing.title')
    return keyPath.split('.').reduce((obj, key) => (obj && obj[key] ? obj[key] : keyPath), dictionary);
  },
  setLanguage: (lang) => set({ language: lang }),
  toggleLanguage: () => set((state) => ({ language: state.language === 'en' ? 'hi' : 'en' }))
}));
